let stats = {};
try {
  stats = $('Get Global Stats').first().json;
} catch (e) {
  stats = { total_jobs: 0, completed_jobs: 0, active_jobs: 0 };
}

const activeItems = $('Get Active Jobs').all();

let text = '<b>📊 НОВЕЛЛЫ: ДАШБОРД ПЕРЕВОДА</b>\n\n';
text += '━━━━━━━━━━━━━━━\n';
text += '📑 <b>Всего заданий:</b> ' + (stats.total_jobs || 0) + '\n';
text += '✅ <b>Завершено:</b> ' + (stats.completed_jobs || 0) + '\n';
text += '⏳ <b>В процессе:</b> ' + (stats.active_jobs || 0) + '\n';
text += '━━━━━━━━━━━━━━━\n';
text += '🧩 <b>Чанков переведено:</b> ' + (stats.total_chunks_translated || 0) + '\n';
text += '💰 <b>Neuro billing:</b>' + (stats.total_neuro/1000 * 79 || 0).toFixed(2) + '\n';
text += '💰 <b>Polza billing:</b>' + ((stats.total_polza/1000 || 0)).toFixed(2) + '\n';
text += '━━━━━━━━━━━━━━━\n';

if (activeItems && activeItems.length > 0 && activeItems[0].json.file_name) {
  text += '\n🔥 <b>АКТИВНЫЕ ЗАДАЧИ:</b>\n';
  activeItems.forEach(item => {
    const job = item.json;
    text += '\n▶️ <code>' + (job.file_name || 'Без имени') + '</code>\n';
    const date = job.created_at ? new Date(job.created_at).toLocaleString('ru-RU') : '---';
    text += '   ↳ <i>Старт: ' + date + '</i>\n';
  });
} else {
  text += '\n🛌 <i>Активных задач нет</i>\n';
}

text += '\n🕒 <i>Обновлено: ' + new Date().toLocaleString('ru-RU') + '</i>';

return { message: text };
